mapper.select:
SELECT COUNT(*)
FROM vehicle
WHERE license_plate = #{licensePlate}

mapper.update:
UPDATE vehicle
SET license_plate = #{licensePlate},
    car_model     = #{carModel}
WHERE vehicle_id = #{vehicleId}

UPDATE vehicle
SET status = 'REJECTED'
WHERE vehicle_id = #{vehicleId}

mapper.select:
SELECT COUNT(*)
FROM vehicle
WHERE status = #{status}
